from flask import Flask, request, jsonify
from datetime import datetime, timedelta
import secrets
import os
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)

# In a real application, these would come from environment variables or a config file
app.config['SECRET_KEY'] = os.environ.get('FLASK_SECRET_KEY', 'a_very_secret_key_for_dev')
app.config['MAIL_SERVER'] = os.environ.get('MAIL_SERVER', 'smtp.mailtrap.io')
app.config['MAIL_PORT'] = int(os.environ.get('MAIL_PORT', 2525))
app.config['MAIL_USERNAME'] = os.environ.get('MAIL_USERNAME', 'your_mailtrap_username')
app.config['MAIL_PASSWORD'] = os.environ.get('MAIL_PASSWORD', 'your_mailtrap_password')
app.config['MAIL_SENDER'] = os.environ.get('MAIL_SENDER', 'no-reply@yourdomain.com')
app.config['FRONTEND_RESET_URL'] = os.environ.get('FRONTEND_RESET_URL', 'http://localhost:3000/reset-password')


# --- Mock Database ---
# In a real application, you'd use SQLAlchemy, Django ORM, etc., with a proper database.
# For MVP, we'll simulate a database with dictionaries.

users_db = {
    "test@example.com": {"password_hash": "some_hashed_password_for_test", "id": 1},
    "user@example.com": {"password_hash": "another_hashed_password", "id": 2},
}

# Stores {token: {"email": "user@example.com", "expires": datetime_object}}
password_reset_tokens = {}

def get_user_by_email(email):
    return users_db.get(email)

def store_reset_token(email, token, expires_at):
    password_reset_tokens[token] = {"email": email, "expires": expires_at}

def get_reset_token_info(token):
    return password_reset_tokens.get(token)

def invalidate_reset_token(token):
    if token in password_reset_tokens:
        del password_reset_tokens[token]
# --- End Mock Database ---


def send_email(to_email, subject, body):
    msg = MIMEText(body)
    msg['Subject'] = subject
    msg['From'] = app.config['MAIL_SENDER']
    msg['To'] = to_email

    try:
        with smtplib.SMTP(app.config['MAIL_SERVER'], app.config['MAIL_PORT']) as server:
            server.starttls()  # Use TLS
            server.login(app.config['MAIL_USERNAME'], app.config['MAIL_PASSWORD'])
            server.send_message(msg)
        return True
    except Exception as e:
        print(f"Error sending email to {to_email}: {e}")
        return False

@app.route('/request-password-reset', methods=['POST'])
def request_password_reset():
    data = request.get_json()
    email = data.get('email')

    if not email:
        return jsonify({"message": "Email is required"}), 400

    user = get_user_by_email(email)

    # Always return a generic success message to prevent email enumeration
    if not user:
        return jsonify({"message": "If an account with that email exists, a password reset link has been sent."}), 200

    token = secrets.token_urlsafe(32) # Generate a random URL-safe token
    expires_at = datetime.utcnow() + timedelta(hours=1) # Token expires in 1 hour

    store_reset_token(email, token, expires_at)

    reset_link = f"{app.config['FRONTEND_RESET_URL']}?token={token}"
    subject = "Password Reset Request"
    body = (
        f"Hi,\n\n"
        f"You have requested a password reset for your account. "
        f"Please click on the following link to reset your password: \n\n"
        f"{reset_link}\n\n"
        f"This link will expire in 1 hour.\n"
        f"If you did not request this, please ignore this email.\n\n"
        f"Thanks,\nYour Application Team"
    )

    if send_email(email, subject, body):
        return jsonify({"message": "If an account with that email exists, a password reset link has been sent."}), 200
    else:
        # In case of email sending failure, log it and return generic success
        # A more robust system might have a retry mechanism or dedicated error handling
        print(f"Failed to send reset email for {email}")
        return jsonify({"message": "If an account with that email exists, a password reset link has been sent."}), 200


if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)